    function populateOrderFlowFromOrder(o,{confirmation=false,reservation=false}={}){reservationMode=!!reservation;resetOrderForm();editMode=!confirmation;editingOrder=reservation?null:(confirmation?null:o);editingReservation=reservation&&!confirmation?o:null;createdOrder=confirmation?o:null;orderCreated=!!confirmation;workItems=orderWorkItems(o).map(i=>({construction:i.constructionType,toothStart:String(i.toothStart),toothEnd:String(i.toothEnd)}));if(!workItems.length)workItems=[{construction:'',toothStart:'',toothEnd:''}];activeWorkItemIndex=workItems.length-1;syncGlobalsFromActive();material=o.material;shade.value=o.shade||'';if(colorNote)colorNote.value=o.colorNote||'';caseName.value=o.caseName||'';extraNote.value=o.notes||'';impression.value=o.impressionDate||toIsoDate(new Date());deadline.value=o.requestedDeliveryDate||'';selectedDate=deadline.value;if(selectedDate)calendarMonth=monthForIso(selectedDate);document.querySelectorAll('#materialChoices .choice').forEach(x=>x.classList.toggle('active',x.dataset.mat===material));renderShadeChoices();renderWorkItemReadouts();completedSteps.add(1);completedSteps.add(2);completedSteps.add(3);if(confirmation){completedSteps.add(4);completedSteps.add(5);step=5;codeEl.textContent=o.shortenedOrderCode||o.orderCode}else step=1;updateSummary();rememberOrderFlowBaseline()}
    async function showNew(rawStep){const wasReservationMode=reservationMode;if(!actor())return options.showLogin?options.showLogin():undefined;reservationMode=false;const requested=validOrderFlowStepOrReplace('new','',rawStep);if(requested==null)return;const didReset=app.classList.contains('hidden')||editMode||orderCreated||wasReservationMode;if(didReset)resetOrderForm();await showShell();editMode=false;editingOrder=null;applyFlowRouteStep(requested);if(didReset)rememberOrderFlowBaseline()}
    async function showNewReservation(rawStep){const wasReservationMode=reservationMode;if(!actor())return options.showLogin?options.showLogin():undefined;reservationMode=true;const requested=validOrderFlowStepOrReplace('reservation-new','',rawStep);if(requested==null)return;const didReset=app.classList.contains('hidden')||editMode||orderCreated||!wasReservationMode;if(didReset)resetOrderForm();if(!impression.value)impression.value=toIsoDate(addDays(new Date(),1));reservationDateSelectionMode='impression';await showShell();reservationMode=true;editMode=false;editingReservation=null;applyFlowRouteStep(requested);if(didReset)rememberOrderFlowBaseline()}
    async function showEdit(orderCode,rawStep){reservationMode=false;if(!actor())return options.showLogin?options.showLogin():undefined;const requested=validOrderFlowStepOrReplace('edit',orderCode,rawStep);if(requested==null)return;if(!(editMode&&editingOrder?.orderCode===orderCode&&!app.classList.contains('hidden'))){try{const o=await loadOrderByCode(orderCode);populateOrderFlowFromOrder(o)}catch(err){if(options.onRouteError)options.onRouteError(err.message||'Could not load order.');await replace('',{skipGuard:true});return}}await showShell();applyFlowRouteStep(requested)}
